Rules.InvariantScript:
// add selected labor items to the job
ForAll(
    colAddLaborItems,
    With(
        {
            varType: "colCdsJobLaborItems",
            varRecordRef: GUID()
        },
        // insert new row in local labor items collection
        Patch(
            colCdsJobLaborItems,
            Defaults(colCdsJobLaborItems),
            {
                appJobIDText: gblRecordJobCurrent.appJobIDText,
                Job: LookUp(
                    colCdsJobs,
                    appJobIDText = gblRecordJobCurrent.appJobIDText
                ),
                'Job Labor Item': varRecordRef,
                'Market Labor Item': LookUp(
                    colCdsMarketLaborItems,
                    'Market Labor Item' = colAddLaborItems[@'Market Labor Item']
                ),
                Name: colAddLaborItems[@Name],
                Quantity: Blank()
            }
        );
        // add labor items to the AUD records collection
        Collect(
            colAUDRecords,
            {
                Type: varType,
                RecordRef: varRecordRef,
                Job: gblRecordJobCurrent.Job,
                Operation: "A"
            }
        );
    )
);
// save local data

IfError( // This line of code is added to hide the errors
If(
    gblAppLoadOffline,
    SaveData(
        colAUDRecords,
        "localAUDRecords"
    );
    SaveData(
        colCdsJobLaborItems,
        "localCdsJobLaborItems"
    );
)
,Blank()) // This line of code is added to hide the errors

;
// leave the screen and reset
Reset(gal_LaborAddItems);
Reset(gal_LaborAddItems__Filter);
Navigate('Labor Screen');
